   "action": "<ACOND () (<OR <ACTION? LEFT> <ACTION? MILKY-WAY>> <COND (<IN? ,TALKING-TREE ,HERE> <LEAVE-TREE \"left\">) (T <TELL \"This time he took the leftmost path. \">)> <TELL ,PATH-TO-MILL> <MOVE-TO ,MILL>) (<OR <ACTION? CENTER> <ACTION? ROAD-TO-RUIN>> <COND (<IN? ,TALKING-TREE ,HERE> <LEAVE-TREE \"center\">) (T <TELL \"This time he took the center path. \">)> <TELL \"Although the path twisted its way through the forest, it had been a more\nimportant thoroughfare long ago, as evidenced by the crumbling stonework lying\nby the wayside. \"> <TELL ,MOAT-DESC> <MOVE-TO ,OUTSIDE-MOAT>) (RIGHT:REMOVE <GUARDED-PATH>) (GARDEN-PATH:REMOVE <GUARDED-PATH>)>",
   "descfcn": null,
