   "synonyms": [],
   "adjectives": [],
   "action": "<ACOND () (EXAMINE:REMOVE <TELL \"The hut was small, made of rough-hewn logs. The thatched roof was so\nhaphazardly constructed that it would hardly keep out the wind, no less\nthe rain. It was difficult to believe that someone would choose to live\nhere, but the evidence clearly pointed in that direction.\" CR CR> <COND (<EQUAL? ,ACTOR ,PRAXIX> <TELL \"\"It would take a good deal of magic to fix this place up,\" Praxix said.\n\"Shall we take a closer look?\"\">) (<EQUAL? ,ACTOR ,ESHER> <TELL \"Esher was not impressed. \"I don't see how someone living here could\nbe of help to anyone,\" he said.\">)>)>",
   "descfcn": null,
   "contfcn": null,
