  "PRSI-TBL": {
   "name": "PRSI-TBL",
   "file": "spells.zil",
   "line": 972,
   "endLine": 988,
   "source": "<ROUTINE PRSI-TBL (STR \"AUX\" (OBJ1 <>) (OBJ2 <>) (OBJ3 <>) (OBJ4 <>) CNT)\n\t <COND (<ZERO? <SET CNT <O-COUNT>>>\n\t\t<SETG ACTION-PRSI <>>\n\t\t<RTRUE>)\n\t       (<EQUAL? .CNT 4>\n\t\t<PRSI-SETUP <GET ,O-TABLE 1> <GET ,O-TABLE 2> <GET ,O-TABLE 3>\n\t\t\t    <GET ,O-TABLE 4>>)\n\t       (<EQUAL? .CNT 3>\n\t\t<PRSI-SETUP <GET ,O-TABLE 1> <GET ,O-TABLE 2> <GET ,O-TABLE 3>>)\n\t       (<EQUAL? .CNT 2>\n\t\t<PRSI-SETUP <GET ,O-TABLE 1> <GET ,O-TABLE 2>>)\n\t       (<EQUAL? .CNT 1>\n\t\t<PRSI-SETUP <GET ,O-TABLE 1>>)>\n\t <COND (<G? .CNT 4>\n\t\t<PRSI-INPUT .STR <>>)\n\t       (T\n\t\t<PRSI-INPUT .STR T>)>>"
  },
  "PRSI-SETUP": {
   "name": "PRSI-SETUP",
   "file": "spells.zil",
   "line": 990,
   "endLine": 1008,
   "source": "<ROUTINE PRSI-SETUP (\"OPTIONAL\" OBJ1 OBJ2 OBJ3 OBJ4 \"AUX\" (CNT 0))\n\t <COND (<AND <ASSIGNED? OBJ1>\n\t\t     <LOC .OBJ1>>\n\t\t<SET CNT <+ .CNT 1>>\n\t\t<PUT ,O-TABLE <+ .CNT 5> .OBJ1>)>\n\t <COND (<AND <ASSIGNED? OBJ2>\n\t\t     <LOC .OBJ2>>\n\t\t<SET CNT <+ .CNT 1>>\n\t\t<PUT ,O-TABLE <+ .CNT 5> .OBJ2>)>\n\t <COND (<AND <ASSIGNED? OBJ3>\n\t\t     <LOC .OBJ3>>\n\t\t<SET CNT <+ .CNT 1>>\n\t\t<PUT ,O-TABLE <+ .CNT 5> .OBJ3>)>\n\t <COND (<AND <ASSIGNED? OBJ4>\n\t\t     <LOC .OBJ4>>\n\t\t<SET CNT <+ .CNT 1>>\n\t\t<PUT ,O-TABLE <+ .CNT 5> .OBJ4>)>\n\t <PUT ,O-TABLE 5 .CNT>\n\t <PUT ,O-TABLE 0 <+ 6 .CNT>>>"
  },
