  "I-SIT-ALONE": {
   "name": "I-SIT-ALONE",
   "kind": "constant",
   "file": "common.zil",
   "line": 269,
   "value": "\"I often sit alone and think of those days; and I long to know what has\nbecome of my many friends who have long since fled across the southern\nseas. I do not know for whom I write this chronicle, yet it seems\nbest that it be told, for soon there will be none who can remember,\nnone who can dream of what was, and someday yet will be.\""
  },
